mapper.command:
-- ============================================================
-- KCT — COMMANDE UNIQUE MAKE.COM (Run a Query)
-- VERSION COMPLÈTE — lecture du JSON COMPLET depuis {{17.result}}
-- 1 seul module postgres:Query
-- Aucun Iterator nécessaire
-- ============================================================

DO $$
DECLARE
    -- =========================
    -- 0) JSON texte brut venant du module 17
    -- =========================
    v_raw_text TEXT := $json${{17.result}}$json$;
    v_payload  JSONB;

    -- =========================
    -- 1) Métadonnées
    -- =========================
    v_doc_id            TEXT;
    v_request_id        TEXT;
    v_model_ocr         TEXT;
    v_num_pages         INT;
    v_created_ts        BIGINT;
    v_doc_numero        TEXT;
    v_date_rapport      DATE;
    v_date_src          TEXT;
    v_heure_dernier     TEXT;
    v_ops_raw           TEXT;
    v_ops_iso           DATE;
    v_op1e              TEXT;
    v_op1s              TEXT;
    v_opds              TEXT;
    v_nb_app            INT;
    v_nb_op             INT;
    v_nb_att            INT;

    -- =========================
    -- 2) Volumes
    -- =========================
    v_import_teu        INT;
    v_export_teu        INT;
    v_transbo_teu       INT;
    v_pleins_teu        INT;
    v_vides_teu         INT;
    v_total_teu         INT;
    v_total_calc        INT;
    v_imp_fc            INT;
    v_exp_fc            INT;
    v_trb_fc            INT;
    v_pln_fc            INT;
    v_vid_fc            INT;
    v_tot_fc            INT;
    v_taux_real         NUMERIC;
    v_ecart_fc          INT;

    -- =========================
    -- 3) Escales armateurs
    -- =========================
    v_cma_p             INT;
    v_cma_r             INT;
    v_cma_t             NUMERIC;
    v_hap_p             INT;
    v_hap_r             INT;
    v_msc_p             INT;
    v_msc_r             INT;
    v_msc_t             NUMERIC;
    v_msk_p             INT;
    v_msk_r             INT;
    v_aut_p             INT;
    v_aut_r             INT;
    v_tot_p             INT;
    v_tot_r             INT;
    v_taux_esc          NUMERIC;

    -- =========================
    -- 4) Parc
    -- =========================
    v_parc_util         INT;
    v_parc_tot          INT;
    v_parc_dispo        INT;
    v_taux_parc         INT;
    v_reef_util         INT;
    v_reef_tot          INT;
    v_reef_dispo        INT;
    v_taux_reef         INT;

    -- =========================
    -- 5) Gate / TTT
    -- =========================
    v_ttt_min           INT;
    v_ttt_cam           INT;
    v_ttt_cont          INT;
    v_gep               INT;
    v_gev               INT;
    v_gsp               INT;
    v_gsv               INT;
    v_g_ent             INT;
    v_g_sor             INT;
    v_g_tot             INT;

    -- =========================
    -- 6) Exploitants
    -- =========================
    v_cma_20s INT;
    v_cma_40s INT;
    v_cma_40h INT;
    v_cma_20p INT;
    v_cma_40p INT;
    v_cma_20r INT;
    v_cma_40r INT;
    v_cma_tot INT;

    v_hlc_20s INT;
    v_hlc_40s INT;
    v_hlc_40h INT;
    v_hlc_20p INT;
    v_hlc_40p INT;
    v_hlc_20r INT;
    v_hlc_40r INT;
    v_hlc_tot INT;

    v_msk_20s INT;
    v_msk_40s INT;
    v_msk_40h INT;
    v_msk_20p INT;
    v_msk_40p INT;
    v_msk_20r INT;
    v_msk_40r INT;
    v_msk_tot INT;

    v_mgs_20s INT;
    v_mgs_40s INT;
    v_mgs_40h INT;
    v_mgs_20p INT;
    v_mgs_40p INT;
    v_mgs_20r INT;
    v_mgs_40r INT;
    v_mgs_tot INT;

    v_t20s INT;
    v_t40s INT;
    v_t40h INT;
    v_t20p INT;
    v_t40p INT;
    v_t20r INT;
    v_t40r INT;
    v_gtot INT;

    -- =========================
    -- 7) KPIs
    -- =========================
    v_np_app   NUMERIC;
    v_np_op    NUMERIC;
    v_teu_prev INT;
    v_teu_rest INT;
    v_util_pct NUMERIC;
    v_ttt_flag TEXT;
    v_gate_pct NUMERIC;

    -- =========================
    -- 8) Clés techniques
    -- =========================
    v_date_id   INT;
    v_rapport_id UUID;

BEGIN
    -- =========================
    -- 9) Cast JSON brut -> JSONB
    -- =========================
    v_payload := v_raw_text::jsonb;

    -- =========================
    -- 10) Extraction des champs simples
    -- =========================
    v_doc_id        := COALESCE(v_payload->>'doc_id', '');
    v_request_id    := COALESCE(v_payload->>'request_id', '');
    v_model_ocr     := COALESCE(v_payload->>'model_ocr', '');
    v_num_pages     := COALESCE((v_payload->>'num_pages')::INT, 0);
    v_created_ts    := COALESCE((v_payload->>'created_timestamp')::BIGINT, 0);
    v_doc_numero    := COALESCE(v_payload->>'document_numero', '');
    v_date_rapport  := NULLIF(v_payload->>'date_rapport', '')::DATE;
    v_date_src      := COALESCE(v_payload->>'date_rapport_source', '');
    v_heure_dernier := COALESCE(v_payload->>'heure_dernier_camion_sorti_raw', '');
    v_ops_raw       := COALESCE(v_payload->>'ops_date_dernier_camion_raw', '');
    v_ops_iso       := NULLIF(v_payload->>'ops_date_dernier_camion_iso', '')::DATE;
    v_op1e          := COALESCE(v_payload->>'ops_1er_camion_entre', '');
    v_op1s          := COALESCE(v_payload->>'ops_1er_camion_sorti', '');
    v_opds          := COALESCE(v_payload->>'ops_dernier_camion_sorti', '');
    v_nb_app        := COALESCE((v_payload->>'nb_navires_appareilles')::INT, 0);
    v_nb_op         := COALESCE((v_payload->>'nb_navires_en_operation')::INT, 0);
    v_nb_att        := COALESCE((v_payload->>'nb_navires_attendus')::INT, 0);

    -- Volumes
    v_import_teu    := COALESCE((v_payload->>'import_teu')::INT, 0);
    v_export_teu    := COALESCE((v_payload->>'export_teu')::INT, 0);
    v_transbo_teu   := COALESCE((v_payload->>'transbo_teu')::INT, 0);
    v_pleins_teu    := COALESCE((v_payload->>'pleins_total_teu')::INT, 0);
    v_vides_teu     := COALESCE((v_payload->>'vides_teu')::INT, 0);
    v_total_teu     := COALESCE((v_payload->>'total_teu')::INT, 0);
    v_total_calc    := COALESCE((v_payload->>'total_teu_calcule')::INT, 0);
    v_imp_fc        := COALESCE((v_payload->>'import_forecast')::INT, 0);
    v_exp_fc        := COALESCE((v_payload->>'export_forecast')::INT, 0);
    v_trb_fc        := COALESCE((v_payload->>'transbo_forecast')::INT, 0);
    v_pln_fc        := COALESCE((v_payload->>'pleins_forecast')::INT, 0);
    v_vid_fc        := COALESCE((v_payload->>'vides_forecast')::INT, 0);
    v_tot_fc        := COALESCE((v_payload->>'total_forecast')::INT, 0);
    v_taux_real     := COALESCE((v_payload->>'taux_realisation_total_pct')::NUMERIC, 0);
    v_ecart_fc      := COALESCE((v_payload->>'ecart_total_forecast')::INT, 0);

    -- Escales
    v_cma_p         := COALESCE((v_payload->>'escales_cma_cgm_prevues')::INT, 0);
    v_cma_r         := COALESCE((v_payload->>'escales_cma_cgm_realisees')::INT, 0);
    v_cma_t         := COALESCE((v_payload->>'escales_cma_cgm_taux_pct')::NUMERIC, 0);
    v_hap_p         := COALESCE((v_payload->>'escales_hapag_lloyd_prevues')::INT, 0);
    v_hap_r         := COALESCE((v_payload->>'escales_hapag_lloyd_realisees')::INT, 0);
    v_msc_p         := COALESCE((v_payload->>'escales_msc_prevues')::INT, 0);
    v_msc_r         := COALESCE((v_payload->>'escales_msc_realisees')::INT, 0);
    v_msc_t         := COALESCE((v_payload->>'escales_msc_taux_pct')::NUMERIC, 0);
    v_msk_p         := COALESCE((v_payload->>'escales_maersk_prevues')::INT, 0);
    v_msk_r         := COALESCE((v_payload->>'escales_maersk_realisees')::INT, 0);
    v_aut_p         := COALESCE((v_payload->>'escales_autres_prevues')::INT, 0);
    v_aut_r         := COALESCE((v_payload->>'escales_autres_realisees')::INT, 0);
    v_tot_p         := COALESCE((v_payload->>'escales_total_prevues')::INT, 0);
    v_tot_r         := COALESCE((v_payload->>'escales_total_realisees')::INT, 0);
    v_taux_esc      := COALESCE((v_payload->>'taux_realisation_escales_pct')::NUMERIC, 0);

    -- Parc
    v_parc_util     := COALESCE((v_payload->>'parc_conteneurs_utilise')::INT, 0);
    v_parc_tot      := COALESCE((v_payload->>'parc_conteneurs_total')::INT, 0);
    v_parc_dispo    := COALESCE((v_payload->>'parc_conteneurs_disponible')::INT, 0);
    v_taux_parc     := COALESCE((v_payload->>'taux_occupation_parc')::INT, 0);
    v_reef_util     := COALESCE((v_payload->>'reefers_utilises')::INT, 0);
    v_reef_tot      := COALESCE((v_payload->>'reefers_total')::INT, 0);
    v_reef_dispo    := COALESCE((v_payload->>'reefers_disponibles')::INT, 0);
    v_taux_reef     := COALESCE((v_payload->>'taux_occupation_reefers')::INT, 0);

    -- Gate / TTT
    v_ttt_min       := COALESCE((v_payload->>'ttt_duree_minutes')::INT, 0);
    v_ttt_cam       := COALESCE((v_payload->>'ttt_total_camions')::INT, 0);
    v_ttt_cont      := COALESCE((v_payload->>'ttt_total_conteneurs')::INT, 0);
    v_gep           := COALESCE((v_payload->>'gate_entrees_pleins')::INT, 0);
    v_gev           := COALESCE((v_payload->>'gate_entrees_vides')::INT, 0);
    v_gsp           := COALESCE((v_payload->>'gate_sorties_pleins')::INT, 0);
    v_gsv           := COALESCE((v_payload->>'gate_sorties_vides')::INT, 0);
    v_g_ent         := COALESCE((v_payload->>'gate_total_entrees')::INT, 0);
    v_g_sor         := COALESCE((v_payload->>'gate_total_sorties')::INT, 0);
    v_g_tot         := COALESCE((v_payload->>'gate_total_mouvements')::INT, 0);

    -- Exploitants
    v_cma_20s := COALESCE((v_payload->>'exp_CMA_20std')::INT, 0);
    v_cma_40s := COALESCE((v_payload->>'exp_CMA_40std')::INT, 0);
    v_cma_40h := COALESCE((v_payload->>'exp_CMA_40htc')::INT, 0);
    v_cma_20p := COALESCE((v_payload->>'exp_CMA_20spe')::INT, 0);
    v_cma_40p := COALESCE((v_payload->>'exp_CMA_40spe')::INT, 0);
    v_cma_20r := COALESCE((v_payload->>'exp_CMA_20rf')::INT, 0);
    v_cma_40r := COALESCE((v_payload->>'exp_CMA_40rf')::INT, 0);
    v_cma_tot := COALESCE((v_payload->>'exp_CMA_total')::INT, 0);

    v_hlc_20s := COALESCE((v_payload->>'exp_HLC_20std')::INT, 0);
    v_hlc_40s := COALESCE((v_payload->>'exp_HLC_40std')::INT, 0);
    v_hlc_40h := COALESCE((v_payload->>'exp_HLC_40htc')::INT, 0);
    v_hlc_20p := COALESCE((v_payload->>'exp_HLC_20spe')::INT, 0);
    v_hlc_40p := COALESCE((v_payload->>'exp_HLC_40spe')::INT, 0);
    v_hlc_20r := COALESCE((v_payload->>'exp_HLC_20rf')::INT, 0);
    v_hlc_40r := COALESCE((v_payload->>'exp_HLC_40rf')::INT, 0);
    v_hlc_tot := COALESCE((v_payload->>'exp_HLC_total')::INT, 0);

    v_msk_20s := COALESCE((v_payload->>'exp_MSK_20std')::INT, 0);
    v_msk_40s := COALESCE((v_payload->>'exp_MSK_40std')::INT, 0);
    v_msk_40h := COALESCE((v_payload->>'exp_MSK_40htc')::INT, 0);
    v_msk_20p := COALESCE((v_payload->>'exp_MSK_20spe')::INT, 0);
    v_msk_40p := COALESCE((v_payload->>'exp_MSK_40spe')::INT, 0);
    v_msk_20r := COALESCE((v_payload->>'exp_MSK_20rf')::INT, 0);
    v_msk_40r := COALESCE((v_payload->>'exp_MSK_40rf')::INT, 0);
    v_msk_tot := COALESCE((v_payload->>'exp_MSK_total')::INT, 0);

    v_mgs_20s := COALESCE((v_payload->>'exp_MGS_20std')::INT, 0);
    v_mgs_40s := COALESCE((v_payload->>'exp_MGS_40std')::INT, 0);
    v_mgs_40h := COALESCE((v_payload->>'exp_MGS_40htc')::INT, 0);
    v_mgs_20p := COALESCE((v_payload->>'exp_MGS_20spe')::INT, 0);
    v_mgs_40p := COALESCE((v_payload->>'exp_MGS_40spe')::INT, 0);
    v_mgs_20r := COALESCE((v_payload->>'exp_MGS_20rf')::INT, 0);
    v_mgs_40r := COALESCE((v_payload->>'exp_MGS_40rf')::INT, 0);
    v_mgs_tot := COALESCE((v_payload->>'exp_MGS_total')::INT, 0);

    v_t20s := COALESCE((v_payload->>'total_20std')::INT, 0);
    v_t40s := COALESCE((v_payload->>'total_40std')::INT, 0);
    v_t40h := COALESCE((v_payload->>'total_40htc')::INT, 0);
    v_t20p := COALESCE((v_payload->>'total_20spe')::INT, 0);
    v_t40p := COALESCE((v_payload->>'total_40spe')::INT, 0);
    v_t20r := COALESCE((v_payload->>'total_20rf')::INT, 0);
    v_t40r := COALESCE((v_payload->>'total_40rf')::INT, 0);
    v_gtot := COALESCE((v_payload->>'exp_grand_total')::INT, 0);

    -- KPIs
    v_np_app   := COALESCE((v_payload->>'kpi_net_prod_moy_appareilles')::NUMERIC, 0);
    v_np_op    := COALESCE((v_payload->>'kpi_net_prod_moy_operation')::NUMERIC, 0);
    v_teu_prev := COALESCE((v_payload->>'kpi_teu_total_maritimes_prevu')::INT, 0);
    v_teu_rest := COALESCE((v_payload->>'kpi_teu_restant_operation')::INT, 0);
    v_util_pct := COALESCE((v_payload->>'kpi_utilisation_globale_pct')::NUMERIC, 0);
    v_ttt_flag := COALESCE(v_payload->>'kpi_ttt_flag', '');
    v_gate_pct := COALESCE((v_payload->>'kpi_gate_ratio_pleins_entrees_pct')::NUMERIC, 0);

    -- =========================
    -- 11) dim_date
    -- =========================
    INSERT INTO kct.dim_date (
        date_id, date_iso, annee, semestre, trimestre, mois_num,
        mois_nom_fr, mois_nom_court_fr, semaine_iso, semaine_label,
        jour_du_mois, jour_de_semaine, jour_nom_fr, jour_nom_court_fr,
        jour_de_annee, est_week_end, est_jour_ferie,
        est_dernier_du_mois, est_premier_du_mois,
        annee_mois, annee_trim, annee_sem
    )
    SELECT
        TO_CHAR(v_date_rapport, 'YYYYMMDD')::INT,
        v_date_rapport,
        EXTRACT(YEAR  FROM v_date_rapport)::SMALLINT,
        CASE WHEN EXTRACT(MONTH FROM v_date_rapport) <= 6 THEN 1 ELSE 2 END::SMALLINT,
        EXTRACT(QUARTER FROM v_date_rapport)::SMALLINT,
        EXTRACT(MONTH FROM v_date_rapport)::SMALLINT,
        CASE EXTRACT(MONTH FROM v_date_rapport)::INT
            WHEN 1 THEN 'Janvier'   WHEN 2 THEN 'Février'   WHEN 3 THEN 'Mars'
            WHEN 4 THEN 'Avril'     WHEN 5 THEN 'Mai'       WHEN 6 THEN 'Juin'
            WHEN 7 THEN 'Juillet'   WHEN 8 THEN 'Août'      WHEN 9 THEN 'Septembre'
            WHEN 10 THEN 'Octobre'  WHEN 11 THEN 'Novembre' WHEN 12 THEN 'Décembre'
        END,
        CASE EXTRACT(MONTH FROM v_date_rapport)::INT
            WHEN 1 THEN 'Janv' WHEN 2 THEN 'Févr' WHEN 3 THEN 'Mars'
            WHEN 4 THEN 'Avr'  WHEN 5 THEN 'Mai'  WHEN 6 THEN 'Juin'
            WHEN 7 THEN 'Juil' WHEN 8 THEN 'Août' WHEN 9 THEN 'Sept'
            WHEN 10 THEN 'Oct' WHEN 11 THEN 'Nov' WHEN 12 THEN 'Déc'
        END,
        EXTRACT(WEEK FROM v_date_rapport)::SMALLINT,
        'S' || LPAD(EXTRACT(WEEK FROM v_date_rapport)::TEXT, 2, '0') || '-' || EXTRACT(YEAR FROM v_date_rapport)::TEXT,
        EXTRACT(DAY FROM v_date_rapport)::SMALLINT,
        EXTRACT(ISODOW FROM v_date_rapport)::SMALLINT,
        CASE EXTRACT(ISODOW FROM v_date_rapport)::INT
            WHEN 1 THEN 'Lundi' WHEN 2 THEN 'Mardi' WHEN 3 THEN 'Mercredi'
            WHEN 4 THEN 'Jeudi' WHEN 5 THEN 'Vendredi' WHEN 6 THEN 'Samedi'
            WHEN 7 THEN 'Dimanche'
        END,
        CASE EXTRACT(ISODOW FROM v_date_rapport)::INT
            WHEN 1 THEN 'Lun' WHEN 2 THEN 'Mar' WHEN 3 THEN 'Mer'
            WHEN 4 THEN 'Jeu' WHEN 5 THEN 'Ven' WHEN 6 THEN 'Sam' WHEN 7 THEN 'Dim'
        END,
        EXTRACT(DOY FROM v_date_rapport)::SMALLINT,
        EXTRACT(ISODOW FROM v_date_rapport) IN (6, 7),
        FALSE,
        (v_date_rapport + INTERVAL '1 day')::date > DATE_TRUNC('month', v_date_rapport) + INTERVAL '1 month',
        EXTRACT(DAY FROM v_date_rapport) = 1,
        TO_CHAR(v_date_rapport, 'YYYY-MM'),
        EXTRACT(YEAR FROM v_date_rapport)::TEXT || '-T' || EXTRACT(QUARTER FROM v_date_rapport)::TEXT,
        EXTRACT(YEAR FROM v_date_rapport)::TEXT || '-S' || CASE WHEN EXTRACT(MONTH FROM v_date_rapport) <= 6 THEN '1' ELSE '2' END
    ON CONFLICT (date_id) DO NOTHING;

    SELECT TO_CHAR(v_date_rapport, 'YYYYMMDD')::INT INTO v_date_id;

    -- =========================
    -- 12) Rapport maître
    -- =========================
    INSERT INTO kct.kct_rapport_quotidien (
        rapport_id, doc_id, request_id, date_id, date_rapport,
        document_numero, model_ocr, num_pages, created_timestamp,
        date_rapport_source, ops_1er_camion_entre, ops_1er_camion_sorti,
        ops_dernier_camion_sorti, ops_date_dernier_camion_raw,
        ops_date_dernier_camion_iso, heure_dernier_camion_raw,
        nb_navires_appareilles, nb_navires_en_operation, nb_navires_attendus,
        source_fichier, inserted_at, updated_at
    ) VALUES (
        gen_random_uuid(), v_doc_id, v_request_id, v_date_id, v_date_rapport,
        v_doc_numero, v_model_ocr, v_num_pages, v_created_ts,
        v_date_src, v_op1e, v_op1s, v_opds, v_ops_raw,
        v_ops_iso, v_heure_dernier,
        v_nb_app, v_nb_op, v_nb_att,
        'make_kct_single_query_raw_result', NOW(), NOW()
    )
    ON CONFLICT (doc_id) DO UPDATE SET
        updated_at                  = NOW(),
        request_id                  = EXCLUDED.request_id,
        date_id                     = EXCLUDED.date_id,
        date_rapport                = EXCLUDED.date_rapport,
        document_numero             = EXCLUDED.document_numero,
        model_ocr                   = EXCLUDED.model_ocr,
        num_pages                   = EXCLUDED.num_pages,
        created_timestamp           = EXCLUDED.created_timestamp,
        date_rapport_source         = EXCLUDED.date_rapport_source,
        ops_1er_camion_entre        = EXCLUDED.ops_1er_camion_entre,
        ops_1er_camion_sorti        = EXCLUDED.ops_1er_camion_sorti,
        ops_dernier_camion_sorti    = EXCLUDED.ops_dernier_camion_sorti,
        ops_date_dernier_camion_raw = EXCLUDED.ops_date_dernier_camion_raw,
        ops_date_dernier_camion_iso = EXCLUDED.ops_date_dernier_camion_iso,
        heure_dernier_camion_raw    = EXCLUDED.heure_dernier_camion_raw,
        nb_navires_appareilles      = EXCLUDED.nb_navires_appareilles,
        nb_navires_en_operation     = EXCLUDED.nb_navires_en_operation,
        nb_navires_attendus         = EXCLUDED.nb_navires_attendus;

    SELECT rapport_id INTO v_rapport_id
    FROM kct.kct_rapport_quotidien
    WHERE doc_id = v_doc_id;

    -- =========================
    -- 13) Volumes
    -- =========================
    INSERT INTO kct.kct_volumes_teu (
        rapport_id, date_id, date_rapport,
        import_teu, export_teu, transbo_teu, pleins_total_teu, vides_teu,
        total_teu, total_teu_calcule,
        import_forecast, export_forecast, transbo_forecast,
        pleins_forecast, vides_forecast, total_forecast,
        taux_realisation_total_pct, ecart_total_forecast
    ) VALUES (
        v_rapport_id, v_date_id, v_date_rapport,
        v_import_teu, v_export_teu, v_transbo_teu, v_pleins_teu, v_vides_teu,
        v_total_teu, v_total_calc,
        v_imp_fc, v_exp_fc, v_trb_fc, v_pln_fc, v_vid_fc, v_tot_fc,
        v_taux_real, v_ecart_fc
    )
    ON CONFLICT (rapport_id) DO UPDATE SET
        import_teu                 = EXCLUDED.import_teu,
        export_teu                 = EXCLUDED.export_teu,
        transbo_teu                = EXCLUDED.transbo_teu,
        pleins_total_teu           = EXCLUDED.pleins_total_teu,
        vides_teu                  = EXCLUDED.vides_teu,
        total_teu                  = EXCLUDED.total_teu,
        total_teu_calcule          = EXCLUDED.total_teu_calcule,
        import_forecast            = EXCLUDED.import_forecast,
        export_forecast            = EXCLUDED.export_forecast,
        transbo_forecast           = EXCLUDED.transbo_forecast,
        pleins_forecast            = EXCLUDED.pleins_forecast,
        vides_forecast             = EXCLUDED.vides_forecast,
        total_forecast             = EXCLUDED.total_forecast,
